from typing import Iterable

def total(values: Iterable[int]) -> int:
    return sum(values)

print('example:', total([2, 3]))

def countdown(n):
    while n > 0:
        yield n
        n -= 1

print('example:', next(countdown(3)))

def identity(fn):
    return fn

@identity
def word():
    return 'ok'

print('example:', word())

